class MyCalendarThree {
public:
    MyCalendarThree() {

    }

    int book(int startTime, int endTime) {
        events_[startTime]++;
        events_[endTime]--;
        int ongoing = 0, k = 0, max_k = 0;
        for (auto& event : events_) {
            ongoing += event.second;
            max_k = max(max_k, k = max(k, ongoing));
        }
        events_.clear();
        return max_k;
    }

private:
    map<int, int> events_;
};
